const listPayrollReconciliationRows = `-- name: ListPayrollReconciliationRows :many
SELECT
    e.id AS employee_id,
    e.user_id,
    e.employee_code,
    e.firstname,
    e.lastname,
    e.email,
    b.branch_name,
    d.name AS department_name,
    ss.id AS salary_slip_id,
    ss.present_days,
    ss.absent_days,
    ss.lwp_days,
    ss.net_salary,
    CASE WHEN ss.id IS NULL THEN 'missing_payslip'
         WHEN ss.absent_days > 0 AND ss.absent_deduction <= 0 THEN 'lop_without_deduction'
         ELSE 'ok'
    END AS reconciliation_status
FROM hrms.employees e
LEFT JOIN hrms.branches b ON b.tenant_id = e.tenant_id AND b.id = e.branch_id AND NOT b.inactive
LEFT JOIN hrms.departments d ON d.tenant_id = e.tenant_id AND d.id = e.department_id AND NOT d.inactive
LEFT JOIN hrms.salary_slips ss ON ss.tenant_id = e.tenant_id AND ss.user_id = e.user_id AND ss.month = $2 AND ss.year = $3 AND NOT ss.inactive
WHERE e.tenant_id = $1 AND NOT e.inactive
ORDER BY reconciliation_status DESC, e.employee_code ASC NULLS LAST, e.firstname ASC
`

type ListPayrollReconciliationRowsParams struct {
	TenantID uuid.UUID `db:"tenant_id" json:"tenant_id"`
	Month    int32     `db:"month" json:"month"`
	Year     int32     `db:"year" json:"year"`
}

type ListPayrollReconciliationRowsRow struct {
	EmployeeID           uuid.UUID      `db:"employee_id" json:"employee_id"`
	UserID               uuid.UUID      `db:"user_id" json:"user_id"`
	EmployeeCode         pgtype.Text    `db:"employee_code" json:"employee_code"`
	Firstname            string         `db:"firstname" json:"firstname"`
	Lastname             pgtype.Text    `db:"lastname" json:"lastname"`
	Email                pgtype.Text    `db:"email" json:"email"`
	BranchName           pgtype.Text    `db:"branch_name" json:"branch_name"`
	DepartmentName       pgtype.Text    `db:"department_name" json:"department_name"`
	SalarySlipID         pgtype.UUID    `db:"salary_slip_id" json:"salary_slip_id"`
	PresentDays          pgtype.Int4    `db:"present_days" json:"present_days"`
	AbsentDays           pgtype.Int4    `db:"absent_days" json:"absent_days"`
	LwpDays              pgtype.Numeric `db:"lwp_days" json:"lwp_days"`
	NetSalary            pgtype.Numeric `db:"net_salary" json:"net_salary"`
	ReconciliationStatus string         `db:"reconciliation_status" json:"reconciliation_status"`
}

func (q *Queries) ListPayrollReconciliationRows(ctx context.Context, arg ListPayrollReconciliationRowsParams) ([]ListPayrollReconciliationRowsRow, error) {
	rows, err := q.db.Query(ctx, listPayrollReconciliationRows, arg.TenantID, arg.Month, arg.Year)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListPayrollReconciliationRowsRow
	for rows.Next() {
		var i ListPayrollReconciliationRowsRow
		if err := rows.Scan(
			&i.EmployeeID,
			&i.UserID,
			&i.EmployeeCode,
			&i.Firstname,
			&i.Lastname,
			&i.Email,
			&i.BranchName,
			&i.DepartmentName,
			&i.SalarySlipID,
			&i.PresentDays,
			&i.AbsentDays,
			&i.LwpDays,
			&i.NetSalary,
			&i.ReconciliationStatus,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

