const resolvePayrollStatutoryRule = `-- name: ResolvePayrollStatutoryRule :one
SELECT id, tenant_id, rule_type, name, state, branch_id, effective_from, effective_to, min_gross_salary, max_gross_salary, employee_amount, employer_amount, frequency, deduction_month, notes, inactive, created_at, created_by, updated_at, updated_by FROM hrms.payroll_statutory_rules
WHERE tenant_id = $1
  AND rule_type = $2
  AND (branch_id IS NULL OR branch_id = $6::uuid)
  AND (state IS NULL OR LOWER(state) = LOWER($7::text))
  AND effective_from <= $3
  AND (effective_to IS NULL OR effective_to >= $3)
  AND (min_gross_salary IS NULL OR min_gross_salary <= $4)
  AND (max_gross_salary IS NULL OR max_gross_salary >= $4)
  AND (deduction_month IS NULL OR deduction_month = $5)
  AND NOT inactive
ORDER BY
  CASE WHEN branch_id = $6::uuid THEN 0 ELSE 1 END,
  CASE WHEN LOWER(state) = LOWER($7::text) THEN 0 ELSE 1 END,
  effective_from DESC
LIMIT 1
`

type ResolvePayrollStatutoryRuleParams struct {
	TenantID       uuid.UUID      `db:"tenant_id" json:"tenant_id"`
	RuleType       string         `db:"rule_type" json:"rule_type"`
	EffectiveFrom  pgtype.Date    `db:"effective_from" json:"effective_from"`
	MinGrossSalary pgtype.Numeric `db:"min_gross_salary" json:"min_gross_salary"`
	DeductionMonth pgtype.Int4    `db:"deduction_month" json:"deduction_month"`
	BranchID       pgtype.UUID    `db:"branch_id" json:"branch_id"`
	State          pgtype.Text    `db:"state" json:"state"`
}

func (q *Queries) ResolvePayrollStatutoryRule(ctx context.Context, arg ResolvePayrollStatutoryRuleParams) (HrmsPayrollStatutoryRule, error) {
	row := q.db.QueryRow(ctx, resolvePayrollStatutoryRule,
		arg.TenantID,
		arg.RuleType,
		arg.EffectiveFrom,
		arg.MinGrossSalary,
		arg.DeductionMonth,
		arg.BranchID,
		arg.State,
	)
	var i HrmsPayrollStatutoryRule
	err := row.Scan(
		&i.ID,
		&i.TenantID,
		&i.RuleType,
		&i.Name,
		&i.State,
		&i.BranchID,
		&i.EffectiveFrom,
		&i.EffectiveTo,
		&i.MinGrossSalary,
		&i.MaxGrossSalary,
		&i.EmployeeAmount,
		&i.EmployerAmount,
		&i.Frequency,
		&i.DeductionMonth,
		&i.Notes,
		&i.Inactive,
		&i.CreatedAt,
		&i.CreatedBy,
		&i.UpdatedAt,
		&i.UpdatedBy,
	)
	return i, err
}

